    displayTitle: "Objective",
    icon: Target,
    body: ( <p> Orbis Empresarial preserves, organizes, and showcases the corporate heritage of Bolivian companies with more than 40 years of trajectory. We digitize archives, certify milestones, and curate living narratives that honor legacy while inspiring the next generation of leaders. </p> ),
    image: '/media/historiapage/bolivia.jpg', 
  },
  {
    id: "mission",
    title: "MISSION",
    displayTitle: "Mission",
    icon: Rocket,
    body: ( <p> To protect the memory of Bolivian enterprise through rigorous documentation, thoughtful storytelling, and timeless design—making each company's journey accessible, verifiable, and beautifully preserved for the future. </p> ),
    image: '/media/historiapage/agropecuario.jpg',
  },
  {
    id: "vision",
    title: "VISION",
    displayTitle: "Vision",
    icon: Eye,
    body: ( <p> A prestigious national archive where the history of business excellence is treasured— a reference for researchers, entrepreneurs, and families that elevates the legacy of Bolivian industry on the world stage. </p> ),
    image: '/media/historiapage/flamingo.jpg',
  },
  {
    id: "origin",
    title: "ORIGIN",
    displayTitle: "Origin",
    icon: History,
    body: ( <p> Born from a commitment to cultural memory, Orbis Empresarial emerged when historians, archivists, and innovators united around a single idea: if we don't document our enterprises today, tomorrow's generations will inherit silence where there should be legacy. </p> ),
    image: '/media/historiapage/salar.jpg', 
  },
];

const howItStartedSection = {
  id: "how",
  title: "HOW IT STARTED",
  displayTitle: "How It Started",
  icon: Telescope,
  body: (
    <div className="w-full">
      <div className="relative py-6 px-4 md:px-0">
        <div className="hidden md:block absolute left-0 right-0 top-10 h-[3px] bg-white" />
        <div className="block md:hidden absolute left-[23px] top-6 bottom-0 w-[1px] bg-gradient-to-b from-transparent via-[#072D42]/20 to-transparent" />
        <ol className="relative z-10 flex flex-col md:flex-row gap-12 md:gap-10 lg:gap-16">
          {[
            { year: "1980s", text: "Foundational archives collected across departments." },
            { year: "1990s", text: "First private–public preservation partnerships." },
            { year: "2000s", text: "Digitization program and certification standards." },
            { year: "2010s", text: "Interactive exhibits and institutional expansion." },
            { year: "Today", text: "A living platform connecting legacy with innovation." },
          ].map((m) => (
            <li key={m.year} className="md:min-w-[160px] md:text-center">
              <div className="hidden md:flex flex-col items-center gap-3">
                <div className="relative"><span className="block w-3 h-3 rounded-full border-2 border-[#072D42]" /></div>
                <div className="text-sm font-light tracking-wide">
                  <span className="font-serif text-lg block mb-1 text-[#072D42]">{m.year}</span>
                  <span className="block max-w-[16rem] text-xs leading-tight text-[#072D42]/80">{m.text}</span>
                </div>
              </div>
              <div className="flex md:hidden items-start gap-4">
                <div className="relative pt-1.5"><span className="block w-3 h-3 rounded-full border-2 border-[#072D42]" /></div>
                <div className="text-sm font-light tracking-wide">
                  <span className="font-serif text-lg block mb-1 text-[#072D42]">{m.year}</span>
                  <span className="block text-xs leading-tight text-[#072D42]/80">{m.text}</span>
                </div>
              </div>
            </li>
          ))}
        </ol>
      </div>
    </div>
  ),
};

const allSections = [...mainSections, howItStartedSection];
const SCROLL_OFFSET = 150;

export default function Index() {
  const [active, setActive] = useState(allSections[0].id);
  const [revealedSections, setRevealedSections] = useState({});
  const sectionRefs = useRef({});
  const [isHeaderShrunk, setIsHeaderShrunk] = useState(false);
  const [scrollY, setScrollY] = useState(0);
  const tickingRef = useRef(false);

  // ⚡ OPTIMIZADO: Scroll con throttling
  useEffect(() => {
    const handleScroll = () => {
      setIsHeaderShrunk(window.scrollY > 100);
      
      if (!tickingRef.current) {
        requestAnimationFrame(() => {
          setScrollY(window.scrollY);
          tickingRef.current = false;
        });
        tickingRef.current = true;
      }
    };
    
    window.addEventListener('scroll', handleScroll, { passive: true });
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  // ⚡ OPTIMIZADO: IntersectionObserver más eficiente
  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach(entry => {
          if (entry.isIntersecting) {
            setActive(entry.target.id);
            setRevealedSections(prev => ({ ...prev, [entry.target.id]: true }));
          }
        });
      },
      { 
        root: null, 
        threshold: 0.3, // ⚡ Solo un threshold
        rootMargin: "-10% 0px -10% 0px" // ⚡ Menos margen
      },
    );

    allSections.forEach((s) => {
      const el = sectionRefs.current[s.id];
      if (el) observer.observe(el);
    });
    
    return () => observer.disconnect();
  }, []);

  const scrollTo = (e, id) => {
    e.preventDefault();
    const el = sectionRefs.current[id];
    if (!el) return;
    
    const elementPosition = el.getBoundingClientRect().top + window.scrollY;
    const offsetPosition = elementPosition - SCROLL_OFFSET;
    
    window.scrollTo({ top: offsetPosition, behavior: "smooth" });
    setActive(id);
  };

  // ⚡ OPTIMIZADO: Sin willChange (causaba lentitud)
  const parallaxStyle = {
    transform: `translate3d(0, ${scrollY * 0.4}px, 0)`
  };

  return (
    <div className="bg-beige text-[#072D42] min-h-screen font-sans">
      {/* HEADER CON EFECTO PARALLAX OPTIMIZADO */}
<div className="h-[80vh] min-h-[400px] max-h-[800px] mb-16 overflow-hidden relative">
        <header className="relative h-full">
          <div 
            className="absolute inset-0 w-full h-full"
            style={parallaxStyle}
          >
            <img 
              src="/media/historiapage/salar.jpg"
              alt="Fondo de Orbis Empresarial"
              className="w-full h-full object-cover"
            />
            <div className="absolute inset-0 bg-black/30"></div>
          </div>
          
          <div className="relative z-30 p-20 lg:p-48 text-white h-full flex flex-col justify-center">
            <h1 className="font-serif text-5xl lg:text-8xl font-normal leading-tight tracking-tight mb-4">
              Orbis<br />Empresarial
            </h1>
            <div className="h-px w-20 mb-6 bg-beige/80"></div>
            <p className="text-lg font-light tracking-wide max-w-md text-beige/90">
              Preserving the living history of Bolivian companies 40+ years strong.
            </p>
          </div>
        </header>
      </div>

      <main className="px-10 py-0">
        {/* NAVEGACIÓN MÓVIL - SOLO EN MÓVIL */}
        <div className="block lg:hidden mb-8">
          <nav className="flex flex-row gap-2 overflow-x-auto py-4">
            {allSections.map((s) => (
              <a
                key={s.id}
                href={`#${s.id}`}
                onClick={(e) => scrollTo(e, s.id)}
                className={`
                  relative text-left py-3 px-4 transition-colors duration-200 whitespace-nowrap
                  rounded-lg border border-[#9298A6]/30 bg-white/10
                  hover:bg-[#9298A6]/10
                  ${
                    active === s.id 
                      ? 'bg-[#9298A6]/20 font-medium'
                      : 'font-light opacity-80 hover:opacity-100'
                  }
                `}
              >
                <span className="tracking-widest text-sm text-[#072D42]">{s.title}</span>
              </a>
            ))}
          </nav>
        </div>

        <div className="flex flex-col lg:flex-row gap-16 lg:items-start">
          {/* ASIDE ORIGINAL - SOLO EN DESKTOP - EXACTAMENTE COMO LO TENÍAS */}
          <aside className="hidden lg:block lg:w-1/5 sticky top-1/4">
            <div 
              className={`
                transition-all duration-700 ease-in-out
                ${isHeaderShrunk 
                  ? 'opacity-100' 
                  : 'opacity-0 -translate-y-4 pointer-events-none'
                }
              `}
            >
              <h2 className="font-serif text-2xl leading-tight mb-4 text-[#072D42]">Orbis<br/>Empresarial</h2>
              <div className="h-px w-16 bg-[#072D42]/50 mb-6"></div>
            </div>

            {/* ⚡ OPTIMIZADO: Sin backdrop-blur (muy costoso) */}
            <nav className="flex lg:flex-col gap-0 rounded-lg overflow-hidden border border-[#9298A6]/30 bg-white/10">
              {allSections.map((s) => (
                <a
                  key={s.id}
                  href={`#${s.id}`}
                  onClick={(e) => scrollTo(e, s.id)}
                  className={`
                    relative text-left py-3 px-4 transition-all duration-300
                    after:content-[''] after:absolute after:left-0 after:bottom-1.5 
                    after:w-full after:h-[1px] after:bg-[#9298A6]
                    after:origin-center after:transition-transform after:duration-300 after:ease-out
                    border-b border-[#9298A6]/20 last:border-b-0
                    hover:bg-[#9298A6]/10
                    ${
                      active === s.id 
                        ? 'font-medium opacity-100 after:scale-x-100 bg-[#9298A6]/20'
                        : 'font-light opacity-70 hover:opacity-100 after:scale-x-0 hover:after:scale-x-100'
                    }
                  `}
                >
                  <span className="tracking-widest text-sm text-[#072D42]">{s.title}</span>
                </a>
              ))}
            </nav>
          </aside>

          <section className="w-full lg:w-4/5 flex flex-col gap-20">
            {mainSections.map((s) => (
              <div
                key={s.id}
                id={s.id}
                ref={(el) => (sectionRefs.current[s.id] = el)}
                className={`
                  scroll-mt-24 bg-white rounded-xl shadow-md border border-[#072D42]/20 hover:border-[#072D42] hover:shadow-lg 
                  overflow-hidden group hover:bg-[#072D42]
                  transform transition-all duration-100 ease-out 
                  ${revealedSections[s.id] ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-8'}
                `}
              >
                <div className={`transition-opacity duration-300 ${active === s.id ? "opacity-100" : "opacity-80"}`}>
                  <div className="flex flex-col md:flex-row">
                    {/* IMAGEN A LA IZQUIERDA - 35% SIN PADDING */}
                    {s.image && (
                      <div className="md:w-[35%] flex order-1 md:order-1">
                        <img 
                          src={s.image} 
                          alt={s.displayTitle} 
                          className="w-full h-full object-cover rounded-l-xl md:rounded-r-none" 
                        />
                      </div>
                    )}
                    
                    {/* TEXTO A LA DERECHA - 65% CON PADDING */}
                    <div className={s.image ? 'md:w-[65%] order-2 md:order-2 p-12 lg:p-16' : 'w-full order-2 p-12 lg:p-16'}>
                      <div className="mb-8">
                        <div className="flex items-center gap-3 mb-4">
                          {/* Icono al lado del título */}
                          <s.icon className="w-6 h-6 text-[#072D42] group-hover:text-white transition-colors duration-300 flex-shrink-0" />
                          <h2 className="font-serif text-3xl font-normal tracking-wide text-[#072D42] group-hover:text-white transition-colors duration-300">
                            {s.displayTitle}
                          </h2>
                        </div>
                        <div className="h-px w-16 bg-[#072D42] group-hover:bg-white transition-colors duration-300 ml-9"></div>
                      </div>
                      <div className="text-lg leading-relaxed font-light tracking-wide text-[#072D42]/95 group-hover:text-white/95 transition-colors duration-300 max-w-prose">
                        {s.body}
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            ))}
            
            {/* Sección "How It Started" con icono */}
            <div 
              id={howItStartedSection.id}
              ref={(el) => (sectionRefs.current[howItStartedSection.id] = el)}
              className={`
                scroll-mt-24 
                transform transition-all duration-700 ease-out
                ${revealedSections[howItStartedSection.id] ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-8'}
              `}
            >
              <div className="mb-8">
                <div className="flex items-center gap-3 mb-4">
                  <howItStartedSection.icon className="w-6 h-6 text-[#072D42]" />
                  <h2 className="font-serif text-3xl font-normal tracking-wide text-[#072D42]">
                    {howItStartedSection.displayTitle}
                  </h2>
                </div>
                <div className="h-px w-16 bg-[#072D42] ml-9"></div>
              </div>
              <div>
                {howItStartedSection.body}
              </div>
            </div>
          </section>
        </div>

        <footer className="mt-24 pt-8 border-t border-[#072D42]/20 text-center max-w-5xl mx-auto">
          <p className="text-sm font-light tracking-wide text-[#072D42]/60">
            © {new Date().getFullYear()} Orbis Empresarial
          </p>
        </footer>
      </main>
    </div>
  );
}
